var deviceId = msg.payload.device_id;
if (!deviceId) {
    var topicParts = (msg.topic || "").split("/");
    deviceId = topicParts.length >= 4 ? topicParts[3] : "device";
}

var activeDevices = context.get("activeDevices") || {};
var now = Date.now();
activeDevices[deviceId] = now;

// Expire devices not seen in the last 5 minutes.
var cutoff = now - (5 * 60 * 1000);
Object.keys(activeDevices).forEach(function(key) {
    if (activeDevices[key] < cutoff) {
        delete activeDevices[key];
    }
});

context.set("activeDevices", activeDevices);
var ids = Object.keys(activeDevices).sort();

return [
    { payload: String(ids.length) },
    { payload: ids.length ? ids.join(", ") : "N/A" },
    { payload: ids.map(function(id) {
        return {
            device_id: id,
            last_seen: new Date(activeDevices[id]).toISOString()
        };
    }) }
];

