var outputs = [null, null, null, null, null];
var indexMap = {"device_01": 0, "device_02": 1, "device_03": 2, "device_04": 3, "device_05": 4};
var idx = indexMap[deviceId];
if (idx === undefined) { return outputs; }
outputs[idx] = msg;
return outputs;

